const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

function onActivity() {
    if (_isIdle) {
        _isIdle = false;
        _dotNetRef.invokeMethodAsync("OnActiveCallback");
    }
    resetTimer();
}

function resetTimer() {
    clearTimeout(_timerId);
    _timerId = setTimeout(() => {
        _isIdle = true;
        _dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, _timeoutMs);
}

export function init(element, dotNetRef, timeoutMs) {
    _element = element;
    _dotNetRef = dotNetRef;
    _timeoutMs = timeoutMs;
    _isIdle = false;
    _controller = new AbortController();

    const opts = { signal: _controller.signal, passive: true };
    for (const evt of events) {
        _element.addEventListener(evt, onActivity, opts);
    }

    resetTimer();
}

export function dispose() {
    clearTimeout(_timerId);
    if (_controller) {
        _controller.abort();
        _controller = null;
    }
}

